import { useState, useEffect, useCallback, useMemo } from 'react';
import { useTranslation } from 'react-i18next';
import { motion, AnimatePresence } from 'framer-motion';
import { 
  FiSearch, 
  FiAlertCircle, 
  FiFilter, 
  FiGrid, 
  FiList,
  FiStar,
  FiClock,
  FiDollarSign,
  FiTrendingUp,
  FiX,
  FiChevronDown,
  FiHeart,
  FiShoppingCart
} from 'react-icons/fi';
import { MenuCardSkeleton } from '../../components/Skeleton/Skeleton';
import { menuAPI, getMediaUrl } from '../../services/api';
import { safeApiCall } from '../../utils/publicApiErrorHandler';
import {
  MenuContainer,
  MenuLayout,
  FilterSidebar,
  MainContent,
  MenuHeader,
  MenuTitle,
  MenuSubtitle,
  MenuControls,
  SearchBar,
  ViewToggle,
  SortDropdown,
  ResultsInfo,
  FilterSection,
  FilterTitle,
  FilterGroup,
  FilterOption,
  PriceRange,
  MenuGrid,
  MenuList,
  NoResults,
  MobileFilterToggle,
  FilterOverlay
} from './Menu.styles';

// Professional E-commerce Style Menu Card
const ProfessionalMenuCard = ({ item, isFood = true, index, viewMode = 'grid' }) => {
  const { t } = useTranslation();
  const [imageLoaded, setImageLoaded] = useState(false);
  const [isFavorite, setIsFavorite] = useState(false);

  const imageUrl = getMediaUrl(item.photo);

  const formatPrice = (price) => {
    if (!price) return t('menu.priceOnRequest');
    return new Intl.NumberFormat('uz-UZ').format(price);
  };

  const handleAddToCart = (e) => {
    e.stopPropagation();
    // TODO: Implement add to cart functionality
    console.log('Added to cart:', item.name);
  };

  const handleToggleFavorite = (e) => {
    e.stopPropagation();
    setIsFavorite(!isFavorite);
  };

  if (viewMode === 'list') {
    return (
      <motion.div
        initial={{ opacity: 0, x: -20 }}
        animate={{ opacity: 1, x: 0 }}
        transition={{ duration: 0.3, delay: index * 0.05 }}
        style={{
          display: 'flex',
          backgroundColor: 'white',
          borderRadius: '16px',
          overflow: 'hidden',
          boxShadow: '0 2px 12px rgba(0,0,0,0.08)',
          border: '1px solid rgba(0,0,0,0.06)',
          cursor: 'pointer',
          transition: 'all 0.3s ease',
          marginBottom: '16px',
          minHeight: '140px'
        }}
        whileHover={{ 
          boxShadow: '0 8px 24px rgba(0,0,0,0.12)',
          transform: 'translateY(-2px)'
        }}
      >
        {/* List Image */}
        <div style={{ 
          width: '200px', 
          height: '140px', 
          position: 'relative',
          flexShrink: 0,
          backgroundColor: '#f8fafc'
        }}>
          <img 
            src={imageUrl || '/images/placeholder-menu.svg'}
            alt={item.name}
            style={{
              width: '100%',
              height: '100%',
              objectFit: 'cover',
              opacity: imageLoaded ? 1 : 0,
              transition: 'opacity 0.3s ease'
            }}
            onLoad={() => setImageLoaded(true)}
            onError={(e) => {
              e.target.src = '/images/placeholder-menu.svg';
              setImageLoaded(true);
            }}
          />
        </div>

        {/* List Content */}
        <div style={{ 
          flex: 1, 
          padding: '20px',
          display: 'flex',
          flexDirection: 'column',
          justifyContent: 'space-between'
        }}>
          <div>
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: '8px' }}>
              <h3 style={{ 
                fontSize: '1.25rem', 
                fontWeight: '700', 
                color: '#1f2937',
                margin: 0,
                lineHeight: '1.3'
              }}>
                {item.name}
              </h3>
              <div style={{ display: 'flex', gap: '8px', alignItems: 'center' }}>
                <div style={{
