        <div>
          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: '8px' }}>
            <h3 style={{ 
              fontSize: '1.3rem', 
              fontWeight: '700', 
              color: '#1f2937',
              lineHeight: '1.3',
              margin: 0,
              flex: 1,
              marginRight: '12px'
            }}>
              {item.name}
            </h3>
            <div style={{
              fontSize: '1.4rem',
              fontWeight: '800',
              color: '#8B4513',
              whiteSpace: 'nowrap'
            }}>
              {formatPrice(item.price)} {item.price ? 'сум' : ''}
            </div>
          </div>

          {/* Description */}
          {isFood && item.ingredients && (
            <p style={{ 
              color: '#6b7280', 
              fontSize: '0.9rem', 
              lineHeight: '1.6',
              margin: 0,
              display: '-webkit-box',
              WebkitLineClamp: 2,
              WebkitBoxOrient: 'vertical',
              overflow: 'hidden'
            }}>
              {item.ingredients}
            </p>
          )}
        </div>

        {/* Nutrition Info */}
        {isFood && (item.calories || item.protein || item.carbs || item.fats) && (
          <div style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(auto-fit, minmax(60px, 1fr))',
            gap: '12px',
            padding: '16px',
            backgroundColor: 'rgba(139, 69, 19, 0.05)',
            borderRadius: '12px',
            border: '1px solid rgba(139, 69, 19, 0.1)'
          }}>
            {item.calories && (
              <div style={{ textAlign: 'center' }}>
                <div style={{ fontSize: '0.7rem', color: '#8B4513', fontWeight: '600', marginBottom: '4px' }}>
                  КАЛОРИИ
                </div>
                <div style={{ fontSize: '1rem', fontWeight: '700', color: '#1f2937' }}>
                  {item.calories}
                </div>
              </div>
            )}
            {item.protein && (
              <div style={{ textAlign: 'center' }}>
                <div style={{ fontSize: '0.7rem', color: '#8B4513', fontWeight: '600', marginBottom: '4px' }}>
                  БЕЛКИ
                </div>
                <div style={{ fontSize: '1rem', fontWeight: '700', color: '#1f2937' }}>
                  {item.protein}г
                </div>
              </div>
            )}
            {item.carbs && (
              <div style={{ textAlign: 'center' }}>
                <div style={{ fontSize: '0.7rem', color: '#8B4513', fontWeight: '600', marginBottom: '4px' }}>
                  УГЛЕВОДЫ
                </div>
                <div style={{ fontSize: '1rem', fontWeight: '700', color: '#1f2937' }}>
                  {item.carbs}г
                </div>
              </div>
            )}
            {item.fats && (
              <div style={{ textAlign: 'center' }}>
                <div style={{ fontSize: '0.7rem', color: '#8B4513', fontWeight: '600', marginBottom: '4px' }}>
                  ЖИРЫ
                </div>
                <div style={{ fontSize: '1rem', fontWeight: '700', color: '#1f2937' }}>
                  {item.fats}г
                </div>
              </div>
            )}
          </div>
        )}

        {/* Beverage Info */}
        {!isFood && (item.volume || item.temperature) && (
          <div style={{
            display: 'flex',
            justifyContent: 'space-around',
            padding: '16px',
            backgroundColor: 'rgba(139, 69, 19, 0.05)',
            borderRadius: '12px',
            border: '1px solid rgba(139, 69, 19, 0.1)'
          }}>
            {item.volume && (
              <div style={{ textAlign: 'center' }}>
                <div style={{ fontSize: '0.7rem', color: '#8B4513', fontWeight: '600', marginBottom: '4px' }}>
                  ОБЪЕМ
                </div>
                <div style={{ fontSize: '1rem', fontWeight: '700', color: '#1f2937' }}>
                  {item.volume}мл
                </div>
              </div>
            )}
            {item.temperature && (
              <div style={{ textAlign: 'center' }}>
                <div style={{ fontSize: '0.7rem', color: '#8B4513', fontWeight: '600', marginBottom: '4px' }}>
                  ПОДАЧА
                </div>
                <div style={{ fontSize: '1rem', fontWeight: '700', color: '#1f2937' }}>
                  {item.temperature === 'hot' ? '🔥 Горячий' : 
                   item.temperature === 'cold' ? '❄️ Холодный' : 
                   '🌡️ Любая'}
                </div>
