          >
            {t('menu.retryButton', 'Try Again')}
          </button>
        )}
        <button
          onClick={() => window.location.href = '/'}
          style={{
            backgroundColor: 'transparent',
            color: '#6F4E37',
            border: '1px solid #6F4E37',
            padding: '0.75rem 1.5rem',
            borderRadius: '8px',
            cursor: 'pointer',
            fontSize: '1rem',
            fontWeight: '500',
            transition: 'all 0.2s'
          }}
          onMouseOver={(e) => {
            e.target.style.backgroundColor = '#6F4E37';
            e.target.style.color = 'white';
          }}
          onMouseOut={(e) => {
